def permutations(words):

  if len(words) == 0:
    return []
  elif len(words) == 1: 
    return [words]
  else:
    perms = []
    for word in words: 
      remaining_words = words[:] 
      remaining_words.remove(word)
      z = permutations(remaining_words)   
      for perm in z: 
        perms.append([word] + perm)
    return perms

