class BinarySearchTree:

    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

    def insert(self, value):
        if value < self.value:
            if self.left is None:
                self.left = BinarySearchTree(value)
            else:
                self.left.insert(value)
        else: 
            if self.right is None:
                self.right = BinarySearchTree(value)
            else:
                self.right.insert(value)

    def contains(self, target):
        if self.value == target:
            return True

        elif target < self.value:
            if self.left is None:
                return False
            else:
                return self.left.contains(target)

        else:
            if self.right is None:
                return False
            else:
                return self.right.contains(target)

import nltk

def detect_language(text):
 tokens = nltk.word_tokenize(text)
 tagged = nltk.pos_tag(tokens)

 language_probabilities = {}

 for i in range(0, len(tagged)):
 if tagged[i][1] in language_probabilities:
 language_probabilities[tagged[i][1]] += 1
 else:
 language_probabilities[tagged[i][1]] = 1

 # Find most probable language
 language = max(language_probabilities, key=lambda key: language_probabilities[key])

 return language

text = 'This is a sentence in English'

language = detect_language(text)

print(language) # Outputs 'English'

def mode(list):
    count_dict = {}
    for item in list:
        if item in count_dict:
            count_dict[item] += 1
        else:
            count_dict[item] = 1

    max_count = 0
    mode = 0
    for key in count_dict.keys():
        if count_dict[key] > max_count:
            max_count = count_dict[key]
            mode = key

    return mode

