def common_elements(list1, list2):
    # Make a copy of list 
    list_copy = list2[:] 

    # Iterate the original list  
    for item in list1: 
        if item in list_copy: 
            list_copy.remove(item) 

    # Return the common elements  
    return list(set(list1) & set(list2))
